#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
using namespace std;
LL n,m,p[50],mid,Ans;map<LL,LL> mp;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int main(){
    n=read(),m=read(),mid=n/2;
    for(LL i=1;i<=n;i++)p[i]=(1ll<<i-1);
    for(LL i=1;i<=m;i++){
        LL x=read(),y=read();
        p[x]|=(1l<<y-1),p[y]|=(1ll<<x-1);
    }Ans=0x3f3f3f3f3f3f3f3f;
    for(LL st=0;st<(1ll<<mid);st++){
        LL now=0,cnt=0;
        for(LL i=1;i<=mid;i++)
            if(st&(1ll<<i-1))now^=p[i],cnt++;
        if(mp.count(now))
            mp[now]=min(mp[now],cnt);
        else mp[now]=cnt;
    }for(LL st=0;st<(1ll<<n-mid);st++){
        LL now=(1ll<<n)-1,cnt=0;
        for(LL i=n;i>mid;i--)
            if(st&(1ll<<n-i))now^=p[i],cnt++;
        if(mp.count(now))
            Ans=min(Ans,cnt+mp[now]);
    }cout<<Ans<<"\n";
    return 0;
}
